import java.util.*;

public class MinCostServers {

    static class Server {
        int cap;
        int cost;

        Server(int cap, int cost) {
            this.cap = cap;
            this.cost = cost;
        }
    }

    public static long minCostRequired(List<Integer> computational,
                                       List<Integer> cost,
                                       int avgcap,
                                       int maxcap) {

        int n = computational.size();

        long currentSum = 0;
        for (int c : computational) {
            currentSum += c;
        }

        long requiredSum = (long) n * avgcap;

        if (currentSum >= requiredSum) {
            return 0;
        }

        long need = requiredSum - currentSum;

        List<Server> servers = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            servers.add(new Server(computational.get(i), cost.get(i)));
        }

        // Sort by cost ascending
        servers.sort(Comparator.comparingInt(s -> s.cost));

        long totalCost = 0;

        for (Server s : servers) {
            if (need <= 0) break;

            int maxIncrease = maxcap - s.cap;
            if (maxIncrease <= 0) continue;

            long increase = Math.min(need, maxIncrease);

            totalCost += increase * s.cost;
            need -= increase;
        }

        return (need > 0) ? -1 : totalCost;
    }
}

